// Validate inputs before any DB operations (S3 — input sanitization)
// tenantId must be a valid UUID; customerPhone must be E.164 format
const data = $json;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const PHONE_RE = /^\+\d{7,15}$/;

if (!data.tenantId || !UUID_RE.test(data.tenantId)) {
  throw new Error(`Invalid tenantId format: ${data.tenantId}`);
}

if (!data.customerPhone || !PHONE_RE.test(data.customerPhone)) {
  throw new Error(`Invalid customerPhone format: ${data.customerPhone}`);
}

// Limit message body length to prevent oversized payloads
const messageBody = (data.body || '').substring(0, 1600);

return [{ json: { ...data, body: messageBody } }];

// Set tenant context variable for all downstream nodes
const tenant = $('DB: Lookup Tenant + System Prompt').first().json;
const inbound = $('Validate Inputs (S3)').first().json;

if (!tenant || !tenant.id) {
  throw new Error(`Tenant not found: ${inbound.tenantId}`);
}

return [{
  json: {
    tenantId: tenant.id,
    billingStatus: tenant.billing_status,
    convUsed: tenant.conv_used_this_cycle,
    convLimit: tenant.conv_limit_this_cycle,
    systemPrompt: tenant.system_prompt,
    customerPhone: inbound.customerPhone,
    messageBody: inbound.body,
    messageSid: inbound.messageSid,
    atSoftLimit: inbound.atSoftLimit ?? false,
    triggerType: inbound.triggerType ?? 'sms_reply',
  }
}];

// Prepare safe message body before DB insert (S3)
// Remove null bytes; body already truncated in Validate Inputs node
const ctx = $('Set Tenant Context (RLS)').first().json;
const convData = $('DB: Get or Create Conversation').first().json;

const rawBody = ctx.triggerType === 'missed_call' ? '(Missed call)' : (ctx.messageBody || '');
// Strip null bytes which can cause issues in some PostgreSQL configs
const safeBody = rawBody.replace(/\x00/g, '');

return [{
  json: {
    tenantId: ctx.tenantId,
    conversationId: convData.conversation_id,
    messageBody: safeBody,
    messageSid: ctx.messageSid ?? ''
  }
}];

// Soft limit response — paid plan, 100% used
return [{
  json: {
    responseText: 'Hi! We\'ve reached our monthly booking limit. Our team will call you back to schedule your appointment. Thank you!',
    conversationId: $('DB: Get or Create Conversation').first().json.conversation_id,
    tenantId: $('Set Tenant Context (RLS)').first().json.tenantId,
    customerPhone: $('Set Tenant Context (RLS)').first().json.customerPhone,
  }
}];
